# Phase gate evaluation — automated checkpoint scoring
from dataclasses import dataclass, field
from enum import Enum

class GateVerdict(Enum):
    PASS    = "advance to next phase"
    HOLD    = "address open items, re-review in 30 days"
    FAIL    = "programme reset required"

@dataclass
class Phase1GateChecklist:
    coe_fte_in_role: int           # must be >= 3
    gateway_sla_documented: bool
    pilot_charters_signed: int     # must be >= 1
    risk_framework_approved: bool  # Legal + CISO sign-off
    llm_contract_executed: bool

    def evaluate(self) -> tuple[GateVerdict, list[str]]:
        issues = []
        if self.coe_fte_in_role < 3:
            issues.append(f"CoE understaffed: {self.coe_fte_in_role}/3 FTE in role")
        if not self.gateway_sla_documented:
            issues.append("LLM gateway SLA not documented")
        if self.pilot_charters_signed < 1:
            issues.append("No pilot charter signed")
        if not self.risk_framework_approved:
            issues.append("Risk framework not approved by Legal + CISO")
        if not self.llm_contract_executed:
            issues.append("Enterprise LLM contract not executed")

        if not issues:
            return GateVerdict.PASS, []
        elif len(issues) <= 2:
            return GateVerdict.HOLD, issues
        else:
            return GateVerdict.FAIL, issues

# Example evaluation
gate = Phase1GateChecklist(
    coe_fte_in_role=4,
    gateway_sla_documented=True,
    pilot_charters_signed=2,
    risk_framework_approved=True,
    llm_contract_executed=True,
)
verdict, issues = gate.evaluate()
print(f"Phase 1 gate: {verdict.value}")
# Phase 1 gate: advance to next phase
